const TEMPO_MAX_INTERVALO_MS = 60000; // 60 segundos – ajuste conforme necessário

// Busca todas as mensagens pendentes (entrada do nó Data Table)
const todas = $input.all().map(item => item.json);
if (todas.length === 0) return [];

// Agrupar por remetente
const porRemetente = new Map();
for (const msg of todas) {
  const rem = msg.remetente;
  if (!porRemetente.has(rem)) porRemetente.set(rem, []);
  porRemetente.get(rem).push(msg);
}

const lotes = [];
const agora = new Date();

for (const [rem, msgs] of porRemetente) {
  // Ordenar por timestamp (crescente)
  msgs.sort((a, b) => new Date(a.timestamp) - new Date(b.timestamp));

  // Última mensagem do remetente
  const ultimaMsg = msgs[msgs.length - 1];
  const tempoUltima = new Date(ultimaMsg.timestamp);
  const idade = agora - tempoUltima;

  // Se a última mensagem tem menos de 60 segundos, aguardar próximo ciclo
  if (idade < TEMPO_MAX_INTERVALO_MS) {
    continue;
  }

  // --- Processar TODAS as mensagens deste remetente (grupo único) ---
  const textos = [];
  const textos_pdf = [];
  let anexos = [];       // Acumula todos os anexos (imagens, PDFs, etc.)
  const ids = [];
  const message_raw_list = [];
  let canal = '';
  let assunto = '';

  for (const msg of msgs) {
    canal = msg.canal;
    assunto = msg.assunto || '';
    if (msg.texto) textos.push(msg.texto);
    if (msg.texto_pdf) textos_pdf.push(msg.texto_pdf);

    // Acumular anexos (importante para múltiplas imagens)
    if (msg.anexos && msg.anexos !== '[]') {
      try {
        let anexosMsg = typeof msg.anexos === 'string' ? JSON.parse(msg.anexos) : msg.anexos;
        if (!Array.isArray(anexosMsg)) anexosMsg = [anexosMsg];
        anexos.push(...anexosMsg);
      } catch (e) {
        console.error('Erro ao parsear anexos da mensagem', msg.id, e);
      }
    }

    if (msg.id) ids.push(msg.id);
    if (msg.message_raw) message_raw_list.push(msg.message_raw);
  }

  const textoCompleto = textos.join('\n\n').trim();
  const textoPdfCompleto = textos_pdf.join('\n\n').trim();

  lotes.push({
    json: {
      canal,
      remetente: rem,
      assunto,
      texto: textoCompleto,
      texto_pdf: textoPdfCompleto,
      anexos: JSON.stringify(anexos),   // Contém todos os anexos do remetente
      message_raw: JSON.stringify(message_raw_list),
      timestamp: new Date().toISOString(),
      ids   // Agora contém TODOS os ids do remetente
    }
  });
}

// Log para depuração (opcional – pode remover depois)
console.log(`Total de lotes gerados: ${lotes.length}`);
if (lotes.length > 0) {
  console.log(`Primeiro lote - remetente: ${lotes[0].json.remetente}, anexos: ${lotes[0].json.anexos}`);
}

return lotes;

// Busca os dados do nó 'Agrupar e Combinar Mensagens' (que tem os ids)
const dadosOriginais = $('Agrupar e Combinar Mensagens').first().json;
const ids = dadosOriginais.ids;

if (!ids || ids.length === 0) {
  return [];
}

// Gera um item para cada id, com o campo 'processado' = "true"
return ids.map(id => ({
  json: {
    id: id,
    processado: "true"
  }
}));

// Junta o bloco de mensagens agrupadas com a memória do cliente
// Espera:
// - nó "Agrupar e Combinar Mensagens"
// - nó "Buscar Memória Cliente" (Data Table com clientes_conversas)

function normalizeText(value) {
  return String(value ?? '').trim();
}

function toNumber(value, fallback = 0) {
  const n = Number(value);
  return Number.isFinite(n) ? n : fallback;
}

function minutesSince(dateValue) {
  if (!dateValue) return null;
  const d = new Date(dateValue);
  if (Number.isNaN(d.getTime())) return null;
  return (Date.now() - d.getTime()) / 60000;
}

const grupo = $('Agrupar e Combinar Mensagens').first().json;

let memoria = null;
try {
  memoria = $('Buscar Memória Cliente').first()?.json ?? null;
} catch (e) {
  memoria = null;
}

const canal_original = normalizeText(grupo.canal || memoria?.canal);
const remetente_original = normalizeText(grupo.remetente || memoria?.cliente_id || memoria?.remetente);

let canal_normalizado = canal_original.toLowerCase();
let remetente_normalizado = remetente_original;

if (canal_normalizado === 'whatsapp' && remetente_normalizado.includes('@s.whatsapp.net')) {
  remetente_normalizado = remetente_normalizado.split('@')[0];
}

const cliente_id = normalizeText(memoria?.cliente_id || remetente_normalizado);

const interacoes = toNumber(memoria?.interacoes, 0);
const ultima_resposta_em = memoria?.ultima_resposta_em ?? null;
const ultimo_canal = normalizeText(memoria?.ultimo_canal || canal_normalizado);
const estado_conversa = normalizeText(memoria?.estado_conversa || 'novo');
const ultima_intencao = memoria?.ultima_intencao ?? null;

const tempo_desde_ultima_resposta_min = minutesSince(ultima_resposta_em);

// Regras de contexto
const primeira_interacao = interacoes === 0 || !memoria;
const conversa_reaberta =
  tempo_desde_ultima_resposta_min !== null && tempo_desde_ultima_resposta_min >= 240;

// Se for primeira interação ou conversa reaberta, pode haver saudação.
// Caso contrário, não saudar novamente.
const saudacao_permitida = primeira_interacao || conversa_reaberta;

let tom_resposta = 'formal';
if (canal_normalizado === 'whatsapp') {
  tom_resposta = saudacao_permitida ? 'natural' : 'directo';
} else if (canal_normalizado === 'email') {
  tom_resposta = 'formal';
}

let contexto_relacionamento = '';
if (primeira_interacao) {
  contexto_relacionamento =
    canal_normalizado === 'whatsapp'
      ? 'Primeiro contacto via WhatsApp: pode saudar de forma natural e acolhedora.'
      : 'Primeiro contacto via email: pode iniciar com uma saudação formal e profissional.';
} else if (conversa_reaberta) {
  contexto_relacionamento =
    canal_normalizado === 'whatsapp'
      ? 'Conversa reaberta após algum tempo: pode saudar de forma breve, sem repetir excessivamente.'
      : 'Conversa reaberta após algum tempo: pode iniciar com uma saudação formal breve.';
} else {
  contexto_relacionamento =
    canal_normalizado === 'whatsapp'
      ? 'Cliente recorrente no WhatsApp: não voltar a saudar; responder de forma directa, natural e objectiva.'
      : 'Cliente recorrente por email: não repetir saudação; responder de forma formal, clara e profissional.';
}

// Bloco final para a IA
const texto_base = normalizeText(grupo.texto || '');
const texto_pdf = normalizeText(grupo.texto_pdf || '');
const texto_completo = [texto_base, texto_pdf].filter(Boolean).join('\n\n').trim();

const payload = {
  // Mantém TODOS os campos originais do grupo exactamente como vieram
  ...grupo,

  // Guardar também versões normalizadas sem mexer nos originais
  canal_original,
  remetente_original,
  canal_normalizado,
  remetente_normalizado,

  // Identificação útil para memória
  cliente_id,

  // Memória / estado
  primeira_interacao,
  saudacao_permitida,
  contexto_relacionamento,
  tom_resposta,
  historial_cliente: {
    interacoes,
    ultima_resposta_em,
    ultimo_canal,
    estado_conversa,
    ultima_intencao,
    tempo_desde_ultima_resposta_min,
    conversa_reaberta,
  },

  // Memória bruta da tabela
  memoria_cliente: memoria ?? null,

  // Texto consolidado para a IA
  texto_enriquecido: texto_completo || grupo.texto || grupo.texto_pdf || '',
};

return [{ json: payload }];
